
CREATE TABLE "public"."configuration_store" ("id" uuid NOT NULL DEFAULT gen_random_uuid(), "config_type" text NOT NULL, "key" text NOT NULL, "value" text NOT NULL, "tenant_id" uuid, "account_id" uuid, "is_active" boolean NOT NULL DEFAULT True, "created_at" timestamp NOT NULL DEFAULT now(), "created_by" uuid, PRIMARY KEY ("id") , FOREIGN KEY ("created_by") REFERENCES "public"."users"("id") ON UPDATE set null ON DELETE set null, FOREIGN KEY ("tenant_id") REFERENCES "public"."tenant"("id") ON UPDATE cascade ON DELETE cascade, FOREIGN KEY ("account_id") REFERENCES "public"."cloud_accounts"("id") ON UPDATE cascade ON DELETE cascade);